import { PrismaClient } from '@prisma/client';
import { exec } from 'child_process';
import { promisify } from 'util';
import * as fs from 'fs';
import * as path from 'path';
import * as zlib from 'zlib';
import { createReadStream, createWriteStream } from 'fs';
import { pipeline } from 'stream/promises';

const execAsync = promisify(exec);
const fsPromises = fs.promises;

interface BackupMetadata {
  id: string;
  filename: string;
  size: number;
  status: 'SUCCESS' | 'FAILED' | 'PENDING';
  timestamp: Date;
  compressedSize?: number;
  originalSize?: number;
  duration?: number; // in milliseconds
  error?: string;
}

interface BackupStats {
  totalBackups: number;
  totalSize: number;
  oldestBackup?: BackupMetadata;
  newestBackup?: BackupMetadata;
  averageSize: number;
}

export class BackupService {
  private prisma: PrismaClient;
  private backupDir: string;
  private metadataFile: string;
  private logger: any;

  constructor() {
    this.prisma = new PrismaClient();
    this.backupDir = path.join(process.cwd(), 'uploads', 'backups');
    this.metadataFile = path.join(this.backupDir, 'backups.json');
    this.logger = console;
    this.initializeBackupDirectory();
  }

  /**
   * Initialize backup directory and metadata file
   */
  private async initializeBackupDirectory(): Promise<void> {
    try {
      if (!fs.existsSync(this.backupDir)) {
        await fsPromises.mkdir(this.backupDir, { recursive: true });
        this.logger.log(`[BackupService] Backup directory created: ${this.backupDir}`);
      }

      if (!fs.existsSync(this.metadataFile)) {
        await fsPromises.writeFile(this.metadataFile, JSON.stringify([], null, 2));
        this.logger.log(`[BackupService] Metadata file initialized`);
      }
    } catch (error) {
      this.logger.error(`[BackupService] Failed to initialize backup directory:`, error);
      throw error;
    }
  }

  /**
   * Load backup metadata from file
   */
  private async loadMetadata(): Promise<BackupMetadata[]> {
    try {
      const data = await fsPromises.readFile(this.metadataFile, 'utf-8');
      return JSON.parse(data);
    } catch (error) {
      this.logger.error(`[BackupService] Failed to load metadata:`, error);
      return [];
    }
  }

  /**
   * Save backup metadata to file
   */
  private async saveMetadata(metadata: BackupMetadata[]): Promise<void> {
    try {
      await fsPromises.writeFile(this.metadataFile, JSON.stringify(metadata, null, 2));
    } catch (error) {
      this.logger.error(`[BackupService] Failed to save metadata:`, error);
      throw error;
    }
  }

  /**
   * Generate backup filename with timestamp
   */
  private generateBackupFilename(): string {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    const hours = String(now.getHours()).padStart(2, '0');
    const minutes = String(now.getMinutes()).padStart(2, '0');
    const seconds = String(now.getSeconds()).padStart(2, '0');

    return `backup-${year}-${month}-${day}-${hours}${minutes}${seconds}.sql.gz`;
  }

  /**
   * Create a database backup
   */
  async createBackup(): Promise<BackupMetadata> {
    const startTime = Date.now();
    const filename = this.generateBackupFilename();
    const backupPath = path.join(this.backupDir, filename);
    const tempSqlPath = path.join(this.backupDir, `${filename}.tmp.sql`);

    const backupId = `backup-${Date.now()}`;
    const metadata: BackupMetadata = {
      id: backupId,
      filename,
      size: 0,
      status: 'PENDING',
      timestamp: new Date(),
    };

    try {
      this.logger.log(`[BackupService] Starting backup creation: ${filename}`);

      // Get database URL from environment
      const databaseUrl = process.env.DATABASE_URL;
      if (!databaseUrl) {
        throw new Error('DATABASE_URL environment variable is not set');
      }

      // Execute pg_dump command
      const { stdout, stderr } = await execAsync(
        `pg_dump "${databaseUrl}" > "${tempSqlPath}"`,
        { maxBuffer: 10 * 1024 * 1024 } // 10MB buffer
      );

      if (stderr && !stderr.includes('warning')) {
        this.logger.warn(`[BackupService] pg_dump warnings: ${stderr}`);
      }

      // Get original file size
      const stats = await fsPromises.stat(tempSqlPath);
      metadata.originalSize = stats.size;

      // Compress the SQL file
      this.logger.log(`[BackupService] Compressing backup: ${filename}`);
      const readStream = createReadStream(tempSqlPath);
      const writeStream = createWriteStream(backupPath);
      const gzipStream = zlib.createGzip();

      await pipeline(readStream, gzipStream, writeStream);

      // Get compressed file size
      const compressedStats = await fsPromises.stat(backupPath);
      metadata.compressedSize = compressedStats.size;
      metadata.size = compressedStats.size;

      // Clean up temporary SQL file
      await fsPromises.unlink(tempSqlPath);

      // Update metadata
      metadata.status = 'SUCCESS';
      metadata.duration = Date.now() - startTime;

      // Save metadata
      const allMetadata = await this.loadMetadata();
      allMetadata.push(metadata);
      await this.saveMetadata(allMetadata);

      this.logger.log(
        `[BackupService] Backup created successfully: ${filename} (${metadata.compressedSize} bytes, ${metadata.duration}ms)`
      );

      return metadata;
    } catch (error: any) {
      this.logger.error(`[BackupService] Backup creation failed:`, error);

      // Clean up temporary files
      try {
        if (fs.existsSync(tempSqlPath)) {
          await fsPromises.unlink(tempSqlPath);
        }
        if (fs.existsSync(backupPath)) {
          await fsPromises.unlink(backupPath);
        }
      } catch (cleanupError) {
        this.logger.error(`[BackupService] Cleanup failed:`, cleanupError);
      }

      metadata.status = 'FAILED';
      metadata.error = error.message;
      metadata.duration = Date.now() - startTime;

      // Save failed metadata
      const allMetadata = await this.loadMetadata();
      allMetadata.push(metadata);
      await this.saveMetadata(allMetadata);

      throw {
        statusCode: 500,
        message: `Backup creation failed: ${error.message}`,
      };
    }
  }

  /**
   * Restore database from backup
   */
  async restoreBackup(backupId: string): Promise<{ success: boolean; message: string }> {
    try {
      this.logger.log(`[BackupService] Starting restore from backup: ${backupId}`);

      // Find backup metadata
      const allMetadata = await this.loadMetadata();
      const backupMetadata = allMetadata.find((b) => b.id === backupId);

      if (!backupMetadata) {
        throw new Error(`Backup not found: ${backupId}`);
      }

      if (backupMetadata.status !== 'SUCCESS') {
        throw new Error(`Cannot restore from failed backup: ${backupMetadata.status}`);
      }

      const backupPath = path.join(this.backupDir, backupMetadata.filename);

      if (!fs.existsSync(backupPath)) {
        throw new Error(`Backup file not found: ${backupPath}`);
      }

      // Get database URL
      const databaseUrl = process.env.DATABASE_URL;
      if (!databaseUrl) {
        throw new Error('DATABASE_URL environment variable is not set');
      }

      // Decompress and restore
      this.logger.log(`[BackupService] Decompressing and restoring backup`);

      const tempSqlPath = path.join(this.backupDir, `restore-${Date.now()}.sql`);
      const readStream = createReadStream(backupPath);
      const writeStream = createWriteStream(tempSqlPath);
      const gunzipStream = zlib.createGunzip();

      await pipeline(readStream, gunzipStream, writeStream);

      // Execute psql restore command
      const { stderr } = await execAsync(
        `psql "${databaseUrl}" < "${tempSqlPath}"`,
        { maxBuffer: 10 * 1024 * 1024 }
      );

      if (stderr && !stderr.includes('warning')) {
        this.logger.warn(`[BackupService] psql warnings: ${stderr}`);
      }

      // Clean up temporary file
      await fsPromises.unlink(tempSqlPath);

      this.logger.log(`[BackupService] Restore completed successfully from: ${backupMetadata.filename}`);

      return {
        success: true,
        message: `Database restored successfully from backup: ${backupMetadata.filename}`,
      };
    } catch (error: any) {
      this.logger.error(`[BackupService] Restore failed:`, error);

      throw {
        statusCode: 500,
        message: `Restore failed: ${error.message}`,
      };
    }
  }

  /**
   * List all backups with metadata
   */
  async listBackups(): Promise<BackupMetadata[]> {
    try {
      this.logger.log(`[BackupService] Listing all backups`);

      const metadata = await this.loadMetadata();

      // Verify files exist and update metadata if needed
      const validBackups: BackupMetadata[] = [];

      for (const backup of metadata) {
        const backupPath = path.join(this.backupDir, backup.filename);

        if (fs.existsSync(backupPath)) {
          const stats = await fsPromises.stat(backupPath);
          backup.size = stats.size;
          validBackups.push(backup);
        } else {
          this.logger.warn(`[BackupService] Backup file not found: ${backup.filename}`);
        }
      }

      // Sort by timestamp descending
      validBackups.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());

      return validBackups;
    } catch (error: any) {
      this.logger.error(`[BackupService] Failed to list backups:`, error);
      throw {
        statusCode: 500,
        message: `Failed to list backups: ${error.message}`,
      };
    }
  }

  /**
   * Delete a backup
   */
  async deleteBackup(backupId: string): Promise<{ success: boolean; message: string }> {
    try {
      this.logger.log(`[BackupService] Deleting backup: ${backupId}`);

      const allMetadata = await this.loadMetadata();
      const backupIndex = allMetadata.findIndex((b) => b.id === backupId);

      if (backupIndex === -1) {
        throw new Error(`Backup not found: ${backupId}`);
      }

      const backup = allMetadata[backupIndex];
      const backupPath = path.join(this.backupDir, backup.filename);

      // Delete file if exists
      if (fs.existsSync(backupPath)) {
        await fsPromises.unlink(backupPath);
        this.logger.log(`[BackupService] Backup file deleted: ${backup.filename}`);
      }

      // Remove from metadata
      allMetadata.splice(backupIndex, 1);
      await this.saveMetadata(allMetadata);

      this.logger.log(`[BackupService] Backup deleted successfully: ${backupId}`);

      return {
        success: true,
        message: `Backup deleted successfully: ${backup.filename}`,
      };
    } catch (error: any) {
      this.logger.error(`[BackupService] Delete failed:`, error);

      throw {
        statusCode: 500,
        message: `Delete failed: ${error.message}`,
      };
    }
  }

  /**
   * Verify backup integrity
   */
  async verifyBackup(backupId: string): Promise<{ valid: boolean; message: string; details?: any }> {
    try {
      this.logger.log(`[BackupService] Verifying backup: ${backupId}`);

      const allMetadata = await this.loadMetadata();
      const backupMetadata = allMetadata.find((b) => b.id === backupId);

      if (!backupMetadata) {
        throw new Error(`Backup not found: ${backupId}`);
      }

      const backupPath = path.join(this.backupDir, backupMetadata.filename);

      if (!fs.existsSync(backupPath)) {
        return {
          valid: false,
          message: `Backup file not found: ${backupMetadata.filename}`,
        };
      }

      // Check file integrity
      const stats = await fsPromises.stat(backupPath);

      if (stats.size === 0) {
        return {
          valid: false,
          message: `Backup file is empty`,
        };
      }

      // Try to decompress a small portion to verify gzip integrity
      try {
        const readStream = createReadStream(backupPath, { end: Math.min(1024, stats.size - 1) });
        const gunzipStream = zlib.createGunzip();
        const writeStream = createWriteStream('/dev/null');

        await pipeline(readStream, gunzipStream, writeStream);
      } catch (error: any) {
        return {
          valid: false,
          message: `Backup file is corrupted: ${error.message}`,
        };
      }

      this.logger.log(`[BackupService] Backup verification passed: ${backupId}`);

      return {
        valid: true,
        message: `Backup is valid and intact`,
        details: {
          filename: backupMetadata.filename,
          size: stats.size,
          compressedSize: backupMetadata.compressedSize,
          originalSize: backupMetadata.originalSize,
          timestamp: backupMetadata.timestamp,
          status: backupMetadata.status,
        },
      };
    } catch (error: any) {
      this.logger.error(`[BackupService] Verification failed:`, error);

      throw {
        statusCode: 500,
        message: `Verification failed: ${error.message}`,
      };
    }
  }

  /**
   * Get backup statistics
   */
  async getBackupStats(): Promise<BackupStats> {
    try {
      this.logger.log(`[BackupService] Calculating backup statistics`);

      const backups = await this.listBackups();

      if (backups.length === 0) {
        return {
          totalBackups: 0,
          totalSize: 0,
          averageSize: 0,
        };
      }

      const totalSize = backups.reduce((sum, backup) => sum + backup.size, 0);
      const averageSize = Math.round(totalSize / backups.length);

      // Sort by timestamp
      const sortedByTime = [...backups].sort(
        (a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );

      const stats: BackupStats = {
        totalBackups: backups.length,
        totalSize,
        averageSize,
        oldestBackup: sortedByTime[0],
        newestBackup: sortedByTime[sortedByTime.length - 1],
      };

      this.logger.log(`[BackupService] Backup stats calculated:`, stats);

      return stats;
    } catch (error: any) {
      this.logger.error(`[BackupService] Failed to calculate stats:`, error);

      throw {
        statusCode: 500,
        message: `Failed to calculate backup statistics: ${error.message}`,
      };
    }
  }

  /**
   * Clean up old backups (keep only last N backups)
   */
  async cleanupOldBackups(keepCount: number = 10): Promise<{ deleted: number; message: string }> {
    try {
      this.logger.log(`[BackupService] Cleaning up old backups (keeping last ${keepCount})`);

      const backups = await this.listBackups();

      if (backups.length <= keepCount) {
        return {
          deleted: 0,
          message: `No backups to delete (current: ${backups.length}, keep: ${keepCount})`,
        };
      }

      const backupsToDelete = backups.slice(keepCount);
      let deletedCount = 0;

      for (const backup of backupsToDelete) {
        try {
          await this.deleteBackup(backup.id);
          deletedCount++;
        } catch (error) {
          this.logger.warn(`[BackupService] Failed to delete backup ${backup.id}:`, error);
        }
      }

      this.logger.log(`[BackupService] Cleanup completed: ${deletedCount} backups deleted`);

      return {
        deleted: deletedCount,
        message: `Cleanup completed: ${deletedCount} old backups deleted`,
      };
    } catch (error: any) {
      this.logger.error(`[BackupService] Cleanup failed:`, error);

      throw {
        statusCode: 500,
        message: `Cleanup failed: ${error.message}`,
      };
    }
  }
}

export const backupService = new BackupService();

import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { backupService } from '../services/backupService';

/**
 * Backup API Routes
 * Provides endpoints for database backup management
 */
export async function backupRoutes(fastify: FastifyInstance) {
  /**
   * POST /api/backups
   * Create a new database backup
   */
  fastify.post('/api/backups', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      // Optional: Add authentication check here
      // await request.jwtVerify();

      const backup = await backupService.createBackup();
      return reply.status(201).send({
        success: true,
        message: 'Backup created successfully',
        data: backup,
      });
    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
        success: false,
        message: error.message || 'Failed to create backup',
      });
    }
  });

  /**
   * GET /api/backups
   * List all available backups
   */
  fastify.get('/api/backups', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      const backups = await backupService.listBackups();
      return reply.status(200).send({
        success: true,
        message: 'Backups retrieved successfully',
        data: backups,
        meta: {
          total: backups.length,
        },
      });
    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
        success: false,
        message: error.message || 'Failed to list backups',
      });
    }
  });

  /**
   * GET /api/backups/stats
   * Get backup statistics
   */
  fastify.get('/api/backups/stats', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      const stats = await backupService.getBackupStats();
      return reply.status(200).send({
        success: true,
        message: 'Backup statistics retrieved successfully',
        data: stats,
      });
    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
        success: false,
        message: error.message || 'Failed to get backup statistics',
      });
    }
  });

  /**
   * GET /api/backups/:id/verify
   * Verify backup integrity
   */
  fastify.get('/api/backups/:id/verify', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      const { id } = request.params as { id: string };

      if (!id) {
        return reply.status(400).send({
          success: false,
          message: 'Backup ID is required',
        });
      }

      const verification = await backupService.verifyBackup(id);
      return reply.status(200).send({
        success: true,
