    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
        success: false,
        message: error.message || 'Failed to verify backup',
      });
    }
  });

  /**
   * POST /api/backups/:id/restore
   * Restore database from backup
   * WARNING: This operation will overwrite the current database
   */
  fastify.post('/api/backups/:id/restore', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      // Optional: Add authentication check here
      // await request.jwtVerify();

      const { id } = request.params as { id: string };

      if (!id) {
        return reply.status(400).send({
          success: false,
          message: 'Backup ID is required',
        });
      }

      // Optional: Require confirmation for restore operations
      const { confirmed } = request.body as { confirmed?: boolean };
      if (!confirmed) {
        return reply.status(400).send({
          success: false,
          message: 'Restore operation requires confirmation. Set confirmed: true in request body.',
        });
      }

      const result = await backupService.restoreBackup(id);
      return reply.status(200).send({
        success: true,
        message: 'Database restored successfully',
        data: result,
      });
    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
        success: false,
        message: error.message || 'Failed to restore backup',
      });
    }
  });

  /**
   * DELETE /api/backups/:id
   * Delete a backup
   */
  fastify.delete('/api/backups/:id', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
