      // await request.jwtVerify();

      const { id } = request.params as { id: string };

      if (!id) {
        return reply.status(400).send({
          success: false,
          message: 'Backup ID is required',
        });
      }

      const result = await backupService.deleteBackup(id);
      return reply.status(200).send({
        success: true,
        message: 'Backup deleted successfully',
        data: result,
      });
    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
        success: false,
        message: error.message || 'Failed to delete backup',
      });
    }
  });

  /**
   * POST /api/backups/cleanup
   * Clean up old backups, keeping only the most recent ones
   */
  fastify.post('/api/backups/cleanup', async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      // Optional: Add authentication check here
      // await request.jwtVerify();

      const { keepCount } = request.body as { keepCount?: number };
      const count = keepCount || 10;

      if (count < 1) {
        return reply.status(400).send({
          success: false,
          message: 'keepCount must be at least 1',
        });
      }

      const result = await backupService.cleanupOldBackups(count);
      return reply.status(200).send({
        success: true,
        message: 'Backup cleanup completed',
        data: result,
      });
    } catch (error: any) {
      const statusCode = error.statusCode || 500;
      return reply.status(statusCode).send({
