import { PrismaClient } from '@prisma/client';
import NodeCache from 'node-cache';

const prisma = new PrismaClient();

// Cache for permissions with 5-minute TTL
const permissionCache = new NodeCache({ stdTTL: 300 });

interface PermissionData {
  name: string;
  description?: string;
  module: string;
  action: string;
}

interface RoleData {
  name: string;
  description?: string;
}

export class PermissionService {
  /**
   * Create a new role
   */
  async createRole(data: RoleData) {
    try {
      const role = await prisma.role.create({
        data: {
          name: data.name,
          description: data.description,
        },
        include: { permissions: { include: { permission: true } } }
      });

      // Clear cache
      permissionCache.flushAll();

      return role;
    } catch (error: any) {
      if (error.code === 'P2002') {
        throw { statusCode: 409, message: `Role "${data.name}" sudah ada` };
      }
      throw { statusCode: 500, message: 'Gagal membuat role' };
    }
  }

  /**
   * Update a role
   */
  async updateRole(roleId: string, data: Partial<RoleData>) {
    try {
      const role = await prisma.role.update({
        where: { id: roleId },
        data: {
          ...(data.name && { name: data.name }),
          ...(data.description !== undefined && { description: data.description }),
        },
        include: { permissions: { include: { permission: true } } }
      });

      // Clear cache
      permissionCache.flushAll();

      return role;
    } catch (error: any) {
      if (error.code === 'P2025') {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }
      if (error.code === 'P2002') {
        throw { statusCode: 409, message: `Role "${data.name}" sudah ada` };
      }
      throw { statusCode: 500, message: 'Gagal mengupdate role' };
    }
  }

  /**
   * Delete a role
   */
  async deleteRole(roleId: string) {
    try {
      // Check if role is in use
      const usersWithRole = await prisma.user.count({
        where: { role: { in: ['SUPER_ADMIN', 'ADMIN', 'EDITOR', 'MODERATOR'] } }
      });

      if (usersWithRole > 0) {
        throw { statusCode: 400, message: 'Role masih digunakan oleh user' };
      }

      await prisma.role.delete({ where: { id: roleId } });

      // Clear cache
      permissionCache.flushAll();

      return { success: true, message: 'Role berhasil dihapus' };
    } catch (error: any) {
      if (error.code === 'P2025') {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }
      throw error;
    }
  }

  /**
   * Assign permission to role
   */
  async assignPermission(roleId: string, permissionId: string) {
    try {
      // Verify role exists
      const role = await prisma.role.findUnique({ where: { id: roleId } });
      if (!role) {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }

      // Verify permission exists
      const permission = await prisma.permission.findUnique({ where: { id: permissionId } });
      if (!permission) {
        throw { statusCode: 404, message: 'Permission tidak ditemukan' };
      }

      const rolePermission = await prisma.rolePermission.create({
        data: {
          roleId,
          permissionId,
        },
        include: { permission: true }
      });

      // Clear cache
      permissionCache.flushAll();

      return rolePermission;
    } catch (error: any) {
      if (error.code === 'P2002') {
        throw { statusCode: 409, message: 'Permission sudah diberikan ke role ini' };
      }
      throw error;
    }
  }

  /**
   * Remove permission from role
   */
  async removePermission(roleId: string, permissionId: string) {
    try {
      await prisma.rolePermission.deleteMany({
        where: {
          roleId,
          permissionId,
        }
      });

      // Clear cache
      permissionCache.flushAll();

      return { success: true, message: 'Permission berhasil dihapus dari role' };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal menghapus permission' };
    }
  }

  /**
   * Check if user has specific permission
   */
  async checkPermission(userId: string, module: string, action: string): Promise<boolean> {
    try {
      // Get cache key
      const cacheKey = `perm_${userId}_${module}_${action}`;
      const cached = permissionCache.get<boolean>(cacheKey);
      if (cached !== undefined) {
        return cached;
      }

      // Get user with role
      const user = await prisma.user.findUnique({
        where: { id: userId },
        select: { role: true }
      });

      if (!user) {
        return false;
      }

      // Super admin has all permissions
      if (user.role === 'SUPER_ADMIN') {
        permissionCache.set(cacheKey, true);
        return true;
      }

      // Check if permission exists for this module/action
      const permission = await prisma.permission.findUnique({
        where: { module_action: { module, action } }
      });

      if (!permission) {
        permissionCache.set(cacheKey, false);
        return false;
      }

      // For now, admin/editor/moderator roles have all permissions
      // In future, this can be extended to check RolePermission junction table
      const hasPermission = ['ADMIN', 'EDITOR', 'MODERATOR'].includes(user.role);
      permissionCache.set(cacheKey, hasPermission);

      return hasPermission;
    } catch (error) {
      console.error('Error checking permission:', error);
      return false;
    }
  }

  /**
   * Get all permissions for a role
   */
  async getRolePermissions(roleId: string) {
    const role = await prisma.role.findUnique({
      where: { id: roleId },
      include: {
        permissions: {
          include: { permission: true }
        }
      }
    });

    if (!role) {
      throw { statusCode: 404, message: 'Role tidak ditemukan' };
    }

    return role;
  }

  /**
   * Get all roles
   */
  async getAllRoles() {
    try {
      const roles = await prisma.role.findMany({
        include: {
          permissions: {
            include: { permission: true }
          }
        },
        orderBy: { createdAt: 'desc' }
      });

      return roles;
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil roles' };
    }
  }

  /**
   * Get all permissions
   */
  async getAllPermissions() {
    try {
      const permissions = await prisma.permission.findMany({
        orderBy: [{ module: 'asc' }, { action: 'asc' }]
      });

      return permissions;
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil permissions' };
    }
  }

  /**
   * Seed default permissions
   */
  async seedDefaultPermissions() {
    try {
      const defaultPermissions: PermissionData[] = [
        // Content permissions
        { name: 'content.create', description: 'Create content', module: 'CONTENT', action: 'CREATE' },
        { name: 'content.read', description: 'Read content', module: 'CONTENT', action: 'READ' },
        { name: 'content.update', description: 'Update content', module: 'CONTENT', action: 'UPDATE' },
        { name: 'content.delete', description: 'Delete content', module: 'CONTENT', action: 'DELETE' },

        // User permissions
        { name: 'user.create', description: 'Create user', module: 'USER', action: 'CREATE' },
        { name: 'user.read', description: 'Read user', module: 'USER', action: 'READ' },
        { name: 'user.update', description: 'Update user', module: 'USER', action: 'UPDATE' },
        { name: 'user.delete', description: 'Delete user', module: 'USER', action: 'DELETE' },

        // Analytics permissions
        { name: 'analytics.read', description: 'Read analytics', module: 'ANALYTICS', action: 'READ' },
        { name: 'analytics.export', description: 'Export analytics', module: 'ANALYTICS', action: 'EXPORT' },

        // Settings permissions
        { name: 'settings.read', description: 'Read settings', module: 'SETTINGS', action: 'READ' },
        { name: 'settings.update', description: 'Update settings', module: 'SETTINGS', action: 'UPDATE' },

        // Role permissions
        { name: 'role.create', description: 'Create role', module: 'ROLE', action: 'CREATE' },
        { name: 'role.read', description: 'Read role', module: 'ROLE', action: 'READ' },
        { name: 'role.update', description: 'Update role', module: 'ROLE', action: 'UPDATE' },
        { name: 'role.delete', description: 'Delete role', module: 'ROLE', action: 'DELETE' },
      ];

      let createdCount = 0;

      for (const perm of defaultPermissions) {
        const existing = await prisma.permission.findUnique({
          where: { module_action: { module: perm.module, action: perm.action } }
        });

        if (!existing) {
          await prisma.permission.create({ data: perm });
          createdCount++;
        }
      }

      console.log(`Seeded ${createdCount} new permissions`);
      return { success: true, message: `Seeded ${createdCount} permissions` };
    } catch (error: any) {
      console.error('Error seeding permissions:', error);
      throw { statusCode: 500, message: 'Gagal seed permissions' };
    }
  }
}

