import { PrismaClient } from '@prisma/client';
import { UAParser } from 'ua-parser-js';

const prisma = new PrismaClient();

interface DateRange {
  startDate?: Date;
  endDate?: Date;
}

interface PageViewData {
  userId?: string;
  path: string;
  referrer?: string;
  userAgent?: string;
}

interface EventData {
  userId?: string;
  eventType: string;
  eventData?: Record<string, any>;
}

interface DeviceInfoData {
  userId?: string;
  deviceType: string;
  os?: string;
  browser?: string;
}

export class AnalyticsService {
  /**
   * Track page view
   */
  async trackPageView(data: PageViewData) {
    try {
      const pageView = await prisma.pageView.create({
        data: {
          userId: data.userId,
          path: data.path,
          referrer: data.referrer,
          userAgent: data.userAgent,
        }
      });

      return pageView;
    } catch (error: any) {
      console.error('Error tracking page view:', error);
      throw { statusCode: 500, message: 'Gagal track page view' };
    }
  }

  /**
   * Track custom event
   */
  async trackEvent(data: EventData) {
    try {
      const event = await prisma.event.create({
        data: {
          userId: data.userId,
          eventType: data.eventType,
          eventData: data.eventData || {},
        }
      });

      return event;
    } catch (error: any) {
      console.error('Error tracking event:', error);
      throw { statusCode: 500, message: 'Gagal track event' };
    }
  }

  /**
   * Track device info
   */
  async trackDeviceInfo(data: DeviceInfoData) {
    try {
      const deviceInfo = await prisma.deviceInfo.create({
        data: {
          userId: data.userId,
          deviceType: data.deviceType,
          os: data.os,
          browser: data.browser,
        }
      });

      return deviceInfo;
    } catch (error: any) {
      console.error('Error tracking device info:', error);
      throw { statusCode: 500, message: 'Gagal track device info' };
    }
  }

  /**
   * Parse user agent and extract device info
   */
  parseUserAgent(userAgent: string) {
    try {
      const parser = new UAParser(userAgent);
      const result = parser.getResult();

      const deviceType = result.device.type || 'DESKTOP';
      const os = result.os.name;
      const browser = result.browser.name;

      return { deviceType, os, browser };
    } catch (error) {
      console.error('Error parsing user agent:', error);
      return { deviceType: 'DESKTOP', os: undefined, browser: undefined };
    }
  }

  /**
   * Get overview statistics
   */
  async getOverviewStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const [totalPageViews, totalEvents, uniqueUsers, totalDevices] = await Promise.all([
        prisma.pageView.count({
          where: { timestamp: { gte: startDate, lte: endDate } }
        }),
        prisma.event.count({
          where: { timestamp: { gte: startDate, lte: endDate } }
        }),
        prisma.pageView.findMany({
          where: { timestamp: { gte: startDate, lte: endDate } },
          distinct: ['userId'],
          select: { userId: true }
        }),
        prisma.deviceInfo.count({
          where: { timestamp: { gte: startDate, lte: endDate } }
        })
      ]);

      return {
        totalPageViews,
        totalEvents,
        uniqueUsers: uniqueUsers.length,
        totalDevices,
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil overview stats' };
    }
  }

  /**
   * Get content performance statistics
   */
  async getContentStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Get page views by content path
      const contentViews = await prisma.pageView.groupBy({
        by: ['path'],
        where: {
          timestamp: { gte: startDate, lte: endDate },
          path: { contains: '/content/' }
        },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 20
      });

      return {
        topContent: contentViews.map(cv => ({
          path: cv.path,
          views: cv._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil content stats' };
    }
  }

  /**
   * Get user growth statistics
   */
  async getUserStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Get new users in date range
      const newUsers = await prisma.user.count({
        where: { createdAt: { gte: startDate, lte: endDate } }
      });

      // Get active users (those with page views)
      const activeUsers = await prisma.pageView.findMany({
        where: { timestamp: { gte: startDate, lte: endDate } },
        distinct: ['userId'],
        select: { userId: true }
      });

      // Get total users
      const totalUsers = await prisma.user.count();

      return {
        newUsers,
        activeUsers: activeUsers.length,
        totalUsers,
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil user stats' };
    }
  }

  /**
   * Get traffic source breakdown
   */
  async getTrafficStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Get referrer breakdown
      const trafficSources = await prisma.pageView.groupBy({
        by: ['referrer'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } }
      });

      return {
        sources: trafficSources.map(ts => ({
          referrer: ts.referrer || 'Direct',
          views: ts._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil traffic stats' };
    }
  }

  /**
   * Get revenue statistics (placeholder for future implementation)
   */
  async getRevenueStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Placeholder - can be extended with actual revenue tracking
      return {
        totalRevenue: 0,
        transactions: 0,
        averageOrderValue: 0,
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil revenue stats' };
    }
  }

  /**
   * Get top pages
   */
  async getTopPages(limit: number = 10, dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const topPages = await prisma.pageView.groupBy({
        by: ['path'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: limit
      });

      return {
        pages: topPages.map(tp => ({
          path: tp.path,
          views: tp._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil top pages' };
    }
  }

  /**
   * Get device breakdown statistics
   */
  async getDeviceStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const deviceStats = await prisma.deviceInfo.groupBy({
        by: ['deviceType'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } }
      });

      const osStats = await prisma.deviceInfo.groupBy({
        by: ['os'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 10
      });

      const browserStats = await prisma.deviceInfo.groupBy({
        by: ['browser'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 10
      });

      return {
        devices: deviceStats.map(ds => ({
          type: ds.deviceType,
          count: ds._count.id
        })),
        operatingSystems: osStats.map(os => ({
          name: os.os || 'Unknown',
          count: os._count.id
        })),
        browsers: browserStats.map(bs => ({
          name: bs.browser || 'Unknown',
          count: bs._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil device stats' };
    }
  }

  /**
   * Get traffic sources
   */
  async getTrafficSources(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const sources = await prisma.pageView.groupBy({
        by: ['referrer'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 20
      });

      return {
        sources: sources.map(s => ({
          referrer: s.referrer || 'Direct',
          views: s._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil traffic sources' };
    }
  }

  /**
   * Get event statistics
   */
  async getEventStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const eventStats = await prisma.event.groupBy({
        by: ['eventType'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } }
      });

      return {
        events: eventStats.map(es => ({
          type: es.eventType,
          count: es._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil event stats' };
    }
  }

  /**
   * Helper: Get date range (default to last 30 days)
   */
  private getDateRange(dateRange?: DateRange) {
    const endDate = dateRange?.endDate || new Date();
    const startDate = dateRange?.startDate || new Date(endDate.getTime() - 30 * 24 * 60 * 60 * 1000);

    return { startDate, endDate };
  }

  /**
   * Clean up old analytics data (older than 90 days)
   */
  async cleanupOldData() {
    try {
      const ninetyDaysAgo = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);

      const [deletedPageViews, deletedEvents, deletedDevices] = await Promise.all([
        prisma.pageView.deleteMany({
          where: { timestamp: { lt: ninetyDaysAgo } }
        }),
        prisma.event.deleteMany({
          where: { timestamp: { lt: ninetyDaysAgo } }
        }),
        prisma.deviceInfo.deleteMany({
          where: { timestamp: { lt: ninetyDaysAgo } }
        })
      ]);

      console.log(`Cleaned up analytics data: ${deletedPageViews.count} page views, ${deletedEvents.count} events, ${deletedDevices.count} device records`);

      return {
        success: true,
        deleted: {
          pageViews: deletedPageViews.count,
          events: deletedEvents.count,
          devices: deletedDevices.count
        }
      };
    } catch (error: any) {
      console.error('Error cleaning up analytics data:', error);
      throw { statusCode: 500, message: 'Gagal cleanup analytics data' };
    }
  }
}

