import { FastifyRequest, FastifyReply } from 'fastify';
import { permissionService } from '../services/permissionService';

/**
 * Middleware: Require specific permission (module + action)
 * Usage: fastify.get('/api/admin/users', { preHandler: [requirePermission('USER', 'READ')] }, handler)
 */
export function requirePermission(module: string, action: string) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
      const { id: userId } = request.user as { id: string };

      const hasPermission = await permissionService.checkPermission(userId, module, action);

      if (!hasPermission) {
        return reply.status(403).send({
          success: false,
          message: `Akses ditolak. Permission ${module}:${action} diperlukan.`
        });
      }
    } catch (err) {
      return reply.status(401).send({
        success: false,
        message: 'Token tidak valid atau sudah expired'
      });
    }
  };
}

/**
 * Middleware: Require specific role
 * Usage: fastify.get('/api/admin/users', { preHandler: [requireRole('ADMIN')] }, handler)
 */
export function requireRole(role: string) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
      const userRole = (request.user as { role: string }).role;

      if (userRole !== role) {
        return reply.status(403).send({
          success: false,
          message: `Akses ditolak. Role ${role} diperlukan.`
        });
      }
    } catch (err) {
      return reply.status(401).send({
        success: false,
        message: 'Token tidak valid atau sudah expired'
      });
    }
  };
}

/**
 * Middleware: Require any of multiple roles
 * Usage: fastify.get('/api/admin/users', { preHandler: [requireAnyRole(['ADMIN', 'EDITOR'])] }, handler)
 */
export function requireAnyRole(roles: string[]) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
      const userRole = (request.user as { role: string }).role;

      if (!roles.includes(userRole)) {
        return reply.status(403).send({
          success: false,
          message: `Akses ditolak. Salah satu role ${roles.join(', ')} diperlukan.`
        });
      }
    } catch (err) {
      return reply.status(401).send({
        success: false,
        message: 'Token tidak valid atau sudah expired'
      });
    }
  };
}

/**
 * Middleware: Require super admin only
 */
export function requireSuperAdminOnly(request: FastifyRequest, reply: FastifyReply) {
  return requireRole('SUPER_ADMIN')(request, reply);
}

import { FastifyRequest, FastifyReply } from 'fastify';
import { analyticsService } from '../services/analyticsService';

/**
 * Middleware: Track page views automatically
 * Non-blocking async tracking
 */
export async function trackPageViewMiddleware(request: FastifyRequest, reply: FastifyReply) {
  try {
    // Extract user ID from JWT if available
    let userId: string | undefined;
    try {
      await request.jwtVerify();
      userId = (request.user as { id: string }).id;
    } catch {
      // User not authenticated, continue without userId
    }

    // Extract device info from user agent
    const userAgent = request.headers['user-agent'] || '';
    const deviceInfo = analyticsService.parseUserAgent(userAgent);

    // Extract referrer
    const referrer = request.headers['referer'] as string | undefined;

    // Track page view asynchronously (non-blocking)
    setImmediate(async () => {
      try {
        await analyticsService.trackPageView({
          userId,
          path: request.url,
          referrer,
          userAgent
        });

        // Track device info if userId is available
        if (userId) {
          await analyticsService.trackDeviceInfo({
            userId,
            deviceType: deviceInfo.deviceType,
            os: deviceInfo.os,
            browser: deviceInfo.browser
          });
        }
      } catch (error) {
        console.error('Error tracking page view:', error);
      }
    });
  } catch (error) {
    console.error('Error in analytics middleware:', error);
  }
}

/**
 * Helper: Track custom event
 * Can be called from route handlers
 */
export async function trackEvent(
  userId: string | undefined,
  eventType: string,
  eventData?: Record<string, any>
) {
  try {
    await analyticsService.trackEvent({
      userId,
      eventType,
      eventData
    });
  } catch (error) {
    console.error('Error tracking event:', error);
  }
}

/**
 * Helper: Track event asynchronously (non-blocking)
 */
export function trackEventAsync(
  userId: string | undefined,
  eventType: string,
  eventData?: Record<string, any>
) {
  setImmediate(() => {
    trackEvent(userId, eventType, eventData).catch(err => {
      console.error('Error in async event tracking:', err);
    });
  });
}

import { FastifyInstance } from 'fastify';
import { permissionService } from '../services/permissionService';
import { requirePermission, requireRole, requireAnyRole } from '../middleware/permissionMiddleware';

export async function permissionRoutes(fastify: FastifyInstance) {
  /**
   * POST /api/admin/roles
   * Create a new role
   */
  fastify.post(
    '/api/admin/roles',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { name, description } = request.body as { name: string; description?: string };

        if (!name) {
          return reply.status(400).send({
            success: false,
            message: 'Nama role wajib diisi'
          });
        }

        const role = await permissionService.createRole({ name, description });

        return {
          success: true,
          message: 'Role berhasil dibuat',
          data: role
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal membuat role'
        });
      }
    }
  );

  /**
   * GET /api/admin/roles
   * List all roles
   */
  fastify.get(
    '/api/admin/roles',
    { preHandler: [requireAnyRole(['SUPER_ADMIN', 'ADMIN'])] },
    async (request, reply) => {
      try {
        const roles = await permissionService.getAllRoles();

        return {
          success: true,
          data: roles
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal mengambil roles'
        });
      }
    }
  );

  /**
   * GET /api/admin/roles/:id
   * Get role by ID with permissions
   */
  fastify.get(
    '/api/admin/roles/:id',
    { preHandler: [requireAnyRole(['SUPER_ADMIN', 'ADMIN'])] },
    async (request, reply) => {
      try {
        const { id } = request.params as { id: string };

        const role = await permissionService.getRolePermissions(id);

        return {
          success: true,
          data: role
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal mengambil role'
        });
      }
    }
  );

  /**
   * PUT /api/admin/roles/:id
   * Update role
   */
  fastify.put(
    '/api/admin/roles/:id',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id } = request.params as { id: string };
        const { name, description } = request.body as { name?: string; description?: string };

        const role = await permissionService.updateRole(id, { name, description });

        return {
          success: true,
          message: 'Role berhasil diupdate',
          data: role
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal mengupdate role'
        });
      }
    }
  );

  /**
   * DELETE /api/admin/roles/:id
   * Delete role
   */
  fastify.delete(
    '/api/admin/roles/:id',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id } = request.params as { id: string };

        const result = await permissionService.deleteRole(id);

        return {
          success: true,
          message: result.message
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal menghapus role'
        });
      }
    }
  );

  /**
   * POST /api/admin/roles/:id/permissions
   * Assign permission to role
   */
  fastify.post(
    '/api/admin/roles/:id/permissions',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id } = request.params as { id: string };
        const { permissionId } = request.body as { permissionId: string };

        if (!permissionId) {
          return reply.status(400).send({
            success: false,
            message: 'Permission ID wajib diisi'
          });
        }

        const rolePermission = await permissionService.assignPermission(id, permissionId);

        return {
          success: true,
          message: 'Permission berhasil diberikan ke role',
          data: rolePermission
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal memberikan permission'
        });
      }
    }
  );

  /**
   * DELETE /api/admin/roles/:id/permissions/:permissionId
   * Remove permission from role
   */
  fastify.delete(
    '/api/admin/roles/:id/permissions/:permissionId',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id, permissionId } = request.params as { id: string; permissionId: string };

        const result = await permissionService.removePermission(id, permissionId);

        return {
          success: true,
          message: result.message
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal menghapus permission'
        });
      }
    }
  );

  /**
   * GET /api/admin/permissions
   * List all permissions
   */
  fastify.get(
    '/api/admin/permissions',
    { preHandler: [requireAnyRole(['SUPER_ADMIN', 'ADMIN'])] },
    async (request, reply) => {
      try {
        const permissions = await permissionService.getAllPermissions();

        // Group by module
        const grouped = permissions.reduce((acc: Record<string, any[]>, perm: any) => {
          if (!acc[perm.module]) {
            acc[perm.module] = [];
          }
          acc[perm.module].push(perm);
          return acc;
        }, {});

        return {
          success: true,
          data: {
            all: permissions,
            grouped
          }
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal mengambil permissions'
        });
      }
    }
  );

  /**
   * POST /api/admin/permissions/seed
   * Seed default permissions
   */
  fastify.post(
    '/api/admin/permissions/seed',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const result = await permissionService.seedDefaultPermissions();

        return {
          success: true,
          message: result.message
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal seed permissions'
        });
      }
    }
  );

  /**
   * GET /api/admin/permissions/check
   * Check if current user has permission
   */
  fastify.get(
    '/api/admin/permissions/check',
    async (request, reply) => {
      try {
        await request.jwtVerify();
        const { id: userId } = request.user as { id: string };
        const { module, action } = request.query as { module: string; action: string };

        if (!module || !action) {
          return reply.status(400).send({
            success: false,
            message: 'Module dan action wajib diisi'
          });
        }

        const hasPermission = await permissionService.checkPermission(userId, module, action);

        return {
          success: true,
          data: {
            module,
            action,
            hasPermission
          }
        };
      } catch (error: any) {
        return reply.status(401).send({
          success: false,
          message: 'Token tidak valid atau sudah expired'
        });
      }
    }
  );
}

