  fastify.post(
    '/api/admin/analytics/cleanup',
    { preHandler: [requireAnyRole(['SUPER_ADMIN'])] },
    async (request, reply) => {
      try {
        const result = await analyticsService.cleanupOldData();

        return {
          success: true,
          message: 'Analytics data berhasil dibersihkan',
          data: result
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal cleanup analytics data'
        });
      }
    }
  );
}
